import{_ as s,o as n,c as a,ag as l}from"./chunks/framework.DGzMGr_a.js";const g=JSON.parse('{"title":"WebSocket：原理、握手、优缺点、vs 长轮询","description":"","frontmatter":{"title":"WebSocket：原理、握手、优缺点、vs 长轮询","difficulty":"medium","tags":["WebSocket","长连接","推送"],"estimate":20},"headers":[],"relativePath":"domains/browser/qa/qa-15-websocket.md","filePath":"domains/browser/qa/qa-15-websocket.md","lastUpdated":1783504823000}'),o={name:"domains/browser/qa/qa-15-websocket.md"};function t(i,e,r,c,p,b){return n(),a("div",null,[...e[0]||(e[0]=[l(`<h1 id="问答-15-进阶-websocket-原理、握手、优缺点、vs-长轮询" tabindex="-1">问答 15（进阶）：WebSocket：原理、握手、优缺点、vs 长轮询 <a class="header-anchor" href="#问答-15-进阶-websocket-原理、握手、优缺点、vs-长轮询" aria-label="Permalink to &quot;问答 15（进阶）：WebSocket：原理、握手、优缺点、vs 长轮询&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>WebSocket 是什么？它的握手过程是怎样的？和 HTTP 长轮询、SSE 相比各有什么优缺点？</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>WebSocket 是什么</strong></p><ul><li>基于 TCP 的<strong>全双工</strong>通信协议，<code>ws://</code> / <code>wss://</code>（加密）。</li><li>建连后，客户端和服务端可<strong>双向、随时</strong>发送二进制或文本帧。</li><li>目的：让浏览器和服务器进行实时、低延迟的双向通信，取代长轮询 / iframe hack。</li></ul><p><strong>握手过程（HTTP Upgrade）</strong></p><p>客户端请求：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /chat HTTP/1.1</span></span>
<span class="line"><span>Host: example.com</span></span>
<span class="line"><span>Upgrade: websocket</span></span>
<span class="line"><span>Connection: Upgrade</span></span>
<span class="line"><span>Sec-WebSocket-Key: dGhlIHNhbXBsZSBub25jZQ==</span></span>
<span class="line"><span>Sec-WebSocket-Version: 13</span></span>
<span class="line"><span>Origin: https://example.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>服务端响应：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>HTTP/1.1 101 Switching Protocols</span></span>
<span class="line"><span>Upgrade: websocket</span></span>
<span class="line"><span>Connection: Upgrade</span></span>
<span class="line"><span>Sec-WebSocket-Accept: s3pPLMBiTxaQ9kYGzzhZRbK+xOo=</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><ul><li><code>Sec-WebSocket-Accept</code> = base64(SHA1(<code>Sec-WebSocket-Key</code> + <code>258EAFA5-E914-47DA-95CA-C5AB0DC85B11</code>))，防止普通 HTTP 服务被误当作 WS 处理。</li><li>握手完成后，同一个 TCP 连接从 HTTP 语义切换成 WebSocket 帧格式，后续不再是 HTTP。</li></ul><p><strong>帧格式（简化）</strong></p><ul><li>FIN 位 + Opcode（text / binary / close / ping / pong / continuation）+ Mask 位 + Payload Length + Masking Key + Payload。</li><li>浏览器发帧<strong>必须 mask</strong>（防中间代理误解析），服务端不用。</li><li>支持大数据分片（continuation frame）、心跳（ping/pong 由协议直接支持）。</li></ul><p><strong>优缺点</strong></p><ul><li><strong>优点</strong>：真正双向、低延迟、开销小（一次握手后每帧 2-14 字节头）；同源策略在 WS 上以 <code>Origin</code> 头由服务端校验。</li><li><strong>缺点</strong>： <ul><li>需要服务端支持长连接（连接数管理、粘性会话、扩容复杂）。</li><li>HTTP 中间设施（CDN、WAF）对 WS 支持参差，可能被超时断开。</li><li>断线重连、协议版本管理需要业务自己处理。</li><li>HTTP/2 / 3 无法自动复用普通连接，需要 <code>RFC 8441</code> 的 WebSocket over HTTP/2（支持少）。</li></ul></li></ul><p><strong>vs 长轮询（long polling）</strong></p><ul><li>长轮询：客户端发一个 HTTP GET，服务器 hold 住直到有数据或超时才返回；返回后客户端立刻再发。</li><li>相比 WebSocket： <ul><li>每次消息都要一次完整 HTTP 请求（header 开销大）。</li><li>单向推送（服务端 → 客户端），客户端要发消息还得再发 HTTP。</li><li>中间设施兼容好，简单实现，适合低频通知。</li></ul></li></ul><p><strong>vs SSE（Server-Sent Events）</strong></p><ul><li>SSE 基于普通 HTTP + <code>Content-Type: text/event-stream</code>，服务器持续写数据流。</li><li>单向（Server → Client），自动重连（<code>Last-Event-ID</code>），事件语义天然。</li><li>优点：走 HTTP，兼容 CDN / 代理更好，客户端 API 简单（<code>EventSource</code>）。</li><li>缺点：单向；旧版 IE 不支持；HTTP/1.1 下受连接数限制（HTTP/2 无此问题）。</li><li>场景：直播弹幕的服务端推送、通知类。</li></ul><p><strong>选型</strong></p><ul><li>双向交互、聊天、协同编辑、游戏 → WebSocket。</li><li>服务端单向广播 → SSE 或 HTTP/2 stream。</li><li>低频消息、老旧网络 → 长轮询。</li><li>音视频 / P2P → WebRTC（DataChannel）。</li></ul><h2 id="追问-1-怎么维护-websocket-的心跳和断线重连" tabindex="-1">追问 1：怎么维护 WebSocket 的心跳和断线重连？ <a class="header-anchor" href="#追问-1-怎么维护-websocket-的心跳和断线重连" aria-label="Permalink to &quot;追问 1：怎么维护 WebSocket 的心跳和断线重连？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>心跳</strong>： <ul><li>协议自带 <code>ping</code> / <code>pong</code> 控制帧，服务端可用。浏览器 JS API 不能主动发 ping，一般在应用层实现：每 N 秒发一条约定的心跳消息（如 <code>{ type: &#39;ping&#39; }</code>），服务端回复。</li><li>心跳周期一般 20-30 秒，短于中间设备（Nginx / LB）的空闲超时。</li><li>若一段时间没收到 pong，判定连接死掉，关闭并重连。</li></ul></li><li><strong>重连</strong>： <ul><li>断开时立刻重连会打爆服务器，采用<strong>指数退避 + 抖动</strong>（0.5s → 1s → 2s → 5s ± 随机）。</li><li>记录最后收到的消息 ID / 版本号，重连后带上做增量拉取，避免丢消息。</li><li>服务端做幂等，防止客户端并发重连产生重复会话。</li></ul></li></ul><h2 id="追问-2-一条-websocket-长连接横向扩容会遇到什么问题" tabindex="-1">追问 2：一条 WebSocket 长连接横向扩容会遇到什么问题？ <a class="header-anchor" href="#追问-2-一条-websocket-长连接横向扩容会遇到什么问题" aria-label="Permalink to &quot;追问 2：一条 WebSocket 长连接横向扩容会遇到什么问题？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>粘性</strong>：客户端断线重连可能路由到不同节点，业务状态（房间 / 会话）需要<strong>跨节点共享</strong>（Redis Pub/Sub、Kafka、集中式状态）。</li><li><strong>广播</strong>：给某个房间的所有连接推消息时，可能这些连接分散在多台机器，需要走消息队列广播到各节点。</li><li><strong>连接数限制</strong>：单机文件描述符、端口、内存都是瓶颈。10 万级要调 <code>ulimit</code>、Linux <code>net.core.somaxconn</code>、<code>net.ipv4.ip_local_port_range</code>；用 epoll / kqueue 高并发实现。</li><li><strong>负载均衡</strong>：普通 LB 按连接分发，扩容时新增节点接不到老连接，冷启动慢。要用一致性哈希或让客户端定期主动重连。</li><li><strong>平滑升级</strong>：滚动发布时要 draining（先摘流、等连接自然掉）。</li><li>生产上常用 Netty / uWebSockets / gnet 之类高性能 IO 框架 + 消息总线（NATS / Kafka）+ 独立会话存储。</li></ul><h2 id="追问-3-能不能在-websocket-上跑-http-like-的请求响应模式-和-grpc-web-有什么关系" tabindex="-1">追问 3：能不能在 WebSocket 上跑 HTTP-like 的请求响应模式？和 gRPC-web 有什么关系？ <a class="header-anchor" href="#追问-3-能不能在-websocket-上跑-http-like-的请求响应模式-和-grpc-web-有什么关系" aria-label="Permalink to &quot;追问 3：能不能在 WebSocket 上跑 HTTP-like 的请求响应模式？和 gRPC-web 有什么关系？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>可以。WebSocket 本身只提供「双向发帧」的能力，开发者可在其上封装任何应用层协议： <ul><li>加个 <code>requestId</code> 字段，客户端发消息时带上，服务端回复用同一个 id，前端根据 id 匹配 pending promise。</li><li>事实上 GraphQL Subscription、STOMP、MQTT over WS、Rsocket 都是这么做的。</li></ul></li><li><strong>gRPC-web</strong>：gRPC 基于 HTTP/2 传输（服务端流、双向流），但浏览器不能直接发 HTTP/2 trailer 帧，因此 gRPC-web 用普通 HTTP/1.1 request-response 或 WebSocket transport 承载，服务端有个 proxy（如 Envoy）转成真正的 gRPC。</li><li>因此在浏览器里跑「双向流」目前主流路径： <ul><li>WebSocket（自定义协议 or STOMP / SocketIO）。</li><li>gRPC-web over WebSocket / fetch streams。</li><li>未来 WebTransport（基于 HTTP/3）会提供更原生的双向流 + 数据报能力。</li></ul></li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/domains/browser/RESOURCES">浏览器 &amp; 网络 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://www.rfc-editor.org/rfc/rfc6455" target="_blank" rel="noreferrer">RFC 6455: WebSocket</a>：WebSocket 协议与握手规范</li><li><a href="https://developer.mozilla.org/en-US/docs/Web/API/WebSockets_API" target="_blank" rel="noreferrer">MDN: WebSocket API</a>：浏览器 WebSocket API 与用法</li><li><a href="https://hpbn.co/websocket/" target="_blank" rel="noreferrer">hpbn.co: WebSocket</a>：WebSocket 架构与性能考量</li></ul>`,34)])])}const u=s(o,[["render",t]]);export{g as __pageData,u as default};
